B.a1a={"French Toast Sticks":0}
B.VW=s(["French toast sticks should be fried for 4 minutes.","Cook in controlled batches so they stay crisp and do not get soggy.","Tell the runner or cook early when you are getting low."],t.s)
B.a0n=new A.aH(B.a1a,[B.VW],t.R)
B.a1s={"Fried Chicken":0}
B.Xj=s(["Confirm fryer setup and safety checks with the cook before starting.","Do not overcrowd the fryer.","Let the cook set the timing and doneness standard for the batch.","Keep the hold pan stocked and the fryer area clean and organized."],t.s)
