B.afH=new A.cF("Harassment & Discrimination","Inform crews of BYU policies on harassment and non-discrimination. Read these policies aloud and get verbal agreement from your crew to treat each other with respect.",null,B.p,B.TZ)
B.Sq=s(["Pull milk in the correct order.","Keep milks on a cart while prepping so the floor stays clear.","Follow the posted shelf sequence in Locker 10 when rotating milk."],t.s)
B.agk=new A.ap("Milk",B.Sq)
B.U9=s(["Consolidate dessert keepers after every shift so Locker 10 does not get overcrowded.","Finish each stack before starting the next stack.","NEVER put donuts or cookies into the lockers."],t.s)
B.ahx=new A.ap("Desserts",B.U9)
B.RJ=s(["Put items only where they belong.","If you are not sure where something goes, ask your supervisor.","Do not put keepers in front of Locker 11.","Do not put keepers or carts in salad bar or deli bar spots. If a spot is empty, keep it empty.","Go to Locker 10 to review expected placement with your crew."],t.s)
B.ahd=new A.ap("Placement Rules",B.RJ)
B.Sd=s([B.agk,B.ahx,B.ahd],t.J)
